    $flaky      = Find-FlakyTests   -Aggregated $aggregated
    $summary    = New-MarkdownSummary -Aggregated $aggregated -FlakyTests $flaky

    if ($OutputPath) {
        Set-Content -Path $OutputPath -Value $summary
        Write-Verbose "Summary written to: $OutputPath"
    }

    return $summary
}

