# ---------------------------------------------------------------------------
if ($InputPath) {
    $summary = Invoke-TestResultsAggregator -InputPath $InputPath -OutputPath $OutputPath
    Write-Host $summary

    if ($env:GITHUB_STEP_SUMMARY) {
        Add-Content -Path $env:GITHUB_STEP_SUMMARY -Value $summary
    }
}

